select:
/* kr.dku.univ.mcqi.tcqi.repository.TcqiMapper.findLcqiSectList */
SELECT CQI_SECT_CD
      ,CQI_TYPE_CD
      ,CHOI_CD
      ,ANS_TYPE_CD
      ,CONT
      ,SORT_ORD
  FROM UNIV.MCQI_SECT_DSC
 WHERE YY         = #{yy}
   AND ORGID      = #{orgid}
   AND PFLT_ID    = #{pfltId}
   AND CQI_DIV_CD = '0002'
 ORDER BY CQI_SECT_CD, CQI_TYPE_CD, SORT_ORD, CHOI_CD

update:
/* kr.dku.univ.mcqi.tcqi.repository.TcqiMapper.mergeLcqiMaster */
MERGE INTO UNIV.MCQI_MASTER TGT
USING DUAL
   ON (    TGT.YY         = #{yy}
       AND TGT.ORGID      = #{orgid}
       AND TGT.PFLT_ID    = #{pfltId}
       AND TGT.CQI_DIV_CD = '0002')
WHEN MATCHED THEN
    UPDATE SET LTST_UPD_UID = #{latestUserId}
              ,LTST_UPD_DM  = SYSDATE
              ,LTST_UPD_IP  = #{remoteAddr}
WHEN NOT MATCHED THEN
    INSERT (YY, ORGID, PFLT_ID, CQI_DIV_CD,
            INPUT_UID, INPUT_DM, INPUT_IP)
    VALUES (#{yy}, #{orgid}, #{pfltId}, '0002',
            #{inputUserId}, SYSDATE, #{remoteAddr})

delete:
/* kr.dku.univ.mcqi.tcqi.repository.TcqiMapper.deleteLcqiSect */
DELETE FROM UNIV.MCQI_SECT_DSC
 WHERE YY         = #{yy}
   AND ORGID      = #{orgid}
   AND PFLT_ID    = #{pfltId}
   AND CQI_DIV_CD = '0002'
   AND CQI_SECT_CD = #{cqiSectCd}
   AND CQI_TYPE_CD = #{cqiTypeCd}

insert:
/* kr.dku.univ.mcqi.tcqi.repository.TcqiMapper.insertLcqiSect */
INSERT INTO UNIV.MCQI_SECT_DSC (
    YY, ORGID, PFLT_ID, CQI_DIV_CD,
    CQI_SECT_CD, CQI_TYPE_CD,
    CHOI_CD, ANS_TYPE_CD, CONT, SORT_ORD,
    INPUT_UID, INPUT_DM, INPUT_IP
) VALUES (
    #{yy}, #{orgid}, #{pfltId}, '0002',
    #{cqiSectCd}, #{cqiTypeCd},
    #{choiCd}, #{ansTypeCd}, #{cont}, #{sortOrd},
    #{inputUserId}, SYSDATE, #{remoteAddr}
)
